#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <omp.h>

#define CHECK_CUDA_ERROR() do { \
    cudaError_t err = cudaGetLastError(); \
    if (err != cudaSuccess) { \
        printf("CUDA error: %s\n", cudaGetErrorString(err)); \
        exit(EXIT_FAILURE); \
    } \
} while(0)

void convolution_1D(float *input, float *mask, float *output, int N, int radius)
{
    int diameter = 2 * radius + 1;

    #pragma omp target teams distribute parallel for map(to: input[0:N], mask[0:diameter]) map(from: output[0:N])
    for (int i = 0; i < N; i++) {
        float result = 0.0f;
        for (int j = -radius; j <= radius; j++) {
            int idx = i + j;
            if (idx >= 0 && idx < N) {
                result += input[idx] * mask[radius - j];
            }
        }
        output[i] = result;
    }
}

int main(int argc, char **argv)
{
    if (argc != 2) {
        printf("Usage: %s <array size>\n", argv[0]);
        return EXIT_FAILURE;
    }
    int N = atoi(argv[1]);
    int radius = 3;
    int diameter = 2 * radius + 1;

    float *input = (float *)malloc(N * sizeof(float));
    float *mask = (float *)malloc(diameter * sizeof(float));
    float *output = (float *)malloc(N * sizeof(float));
    float *output_ref = (float *)malloc(N * sizeof(float));

    if (!input || !mask || !output || !output_ref) {
        printf("Memory allocation failed\n");
        return EXIT_FAILURE;
    }

    // Initialize input and mask arrays
    for (int i = 0; i < N; i++) {
        input[i] = static_cast<float>(i % 256) / 255.0f;
    }
    for (int i = 0; i < diameter; i++) {
        mask[i] = 1.0f / diameter;
    }

    // Compute reference output on host
    for (int i = 0; i < N; i++) {
        float result = 0.0f;
        for (int j = -radius; j <= radius; j++) {
            int idx = i + j;
            if (idx >= 0 && idx < N) {
                result += input[idx] * mask[radius - j];
            }
        }
        output_ref[i] = result;
    }

    // Run convolution on device using OpenMP target offload
    convolution_1D(input, mask, output, N, radius);

    // Verify results
    int errors = 0;
    for (int i = 0; i < N; i++) {
        if (fabs(output[i] - output_ref[i]) > 1e-5f) {
            errors++;
        }
    }

    if (errors) {
        printf("Test FAILED with %d errors\n", errors);
    } else {
        printf("Test PASSED\n");
    }

    free(input);
    free(mask);
    free(output);
    free(output_ref);

    return 0;
}
